    // --- Device Discovery ---

    fun discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        path: String = "/info",
        useHttps: Boolean = false,
        callback: DeviceDiscoveryCallback
    ) {
        val discoveredDevices = mutableListOf<DeviceInfo>()
        var completedRequests = 0
        val totalRequests = 254

        for (i in 1..254) {
            val ip = "$subnet.$i"
            val scheme = if (useHttps) "https" else "http"
            val url = "$scheme://$ip:$port$path"

            val request = Request.Builder()
                .url(url)
                .get()
                .build()

            localClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    synchronized(this@IoTHttpClient) {
                        completedRequests++
                        if (completedRequests >= totalRequests) {
                            callback.onDiscoveryComplete(discoveredDevices)
                        }
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    synchronized(this@IoTHttpClient) {
                        if (response.isSuccessful) {
                            val body = response.body?.string()
                            discoveredDevices.add(DeviceInfo(ip, port, body))
                            callback.onDeviceFound(DeviceInfo(ip, port, body))
                        }
                        response.close()
                        completedRequests++
                        if (completedRequests >= totalRequests) {
                            callback.onDiscoveryComplete(discoveredDevices)
                        }
                    }
                }
            })
        }
    }

